    'agency.forBrokerages': 'Für Immobilienunternehmen',
    'agency.hero': 'Jedes Angebot wird zum Erlebnis',
    'agency.heroDescription': 'Room verwandelt offene Häuser von Durchgängen in Design-Explorationen. Käufer engagieren sich länger, stellen sich tiefer vor und erinnern sich an Ihre Angebote.',
    'agency.seeHowItWorks': 'Sehen Sie, wie es funktioniert',
    'agency.viewEngagementData': 'Engagement-Daten anzeigen',
    'agency.whatChanges': 'Was sich ändert',
    'agency.longerVisits': 'Längere Besuche',
    'agency.longerVisitsDesc': 'Käufer, die Raum-für-Raum-QR-Codes scannen, verbringen messbar mehr Zeit bei offenen Häusern. Sie erkunden Designmöglichkeiten, statt nur zu schauen und zu gehen.',
    'agency.deeperEngagement': 'Tieferes Engagement',
    'agency.deeperEngagementDesc': 'Jede Designrichtung ist ein Gesprächseinstieg. Käufer sehen, was der Raum werden könnte, nicht nur was er ist. Sie kehren nach dem Besuch zur Angebots-Seite zurück.',
    'agency.brandElevated': 'Ihre Marke, aufgewertet',
    'agency.brandElevatedDesc': 'Jede Angebots-Seite verlinkt zu Ihrem Maklerbüro. Jede Design-Präsentation nennt Ihren Makler. Premium-QR-Karten an jedem Lichtschalter tragen Ihre Identität. Dies ist Ihr Werkzeug.',
    'agency.forYourAgents': 'Für Ihre Makler',
    'agency.threeSteps': 'Drei Schritte. Unter fünf Minuten.',
    'agency.noSkillsNeeded': 'Ihre Makler benötigen keine Design-Fähigkeiten, technisches Wissen oder Schulung. Das Tool erledigt die Arbeit.',
    'agency.step1Title': 'Angebots-URL einfügen',
    'agency.step1Desc': 'Makler fügt die Angebots-URL von jeder Makler-Website ein. Room scannt die Fotos, identifiziert Räume und generiert automatisch KI-Designrichtungen.',
    'agency.step2Title': 'Prüfen und veröffentlichen',
    'agency.step2Desc': 'Makler prüft die generierten Designs, kuratiert die besten und veröffentlicht das Angebot mit einem Klick. Die öffentliche Angebots-Seite ist sofort live.',
    'agency.step3Title': 'QR-Karten bestellen',
    'agency.step3Desc': 'Eine Karte für die Haustür, eine für jeden Raum. Premium 32pt-Quadratkarten direkt versandt. Platzieren Sie sie bei den Lichtschaltern beim offenen Haus.',
    'agency.physicalProduct': 'Physisches Produkt',
    'agency.cardsFeel': 'Karten, die sich wie das Angebot anfühlen',
    'agency.cardsDesc1': '32-Punkt-Luxe-Karton. 600gsm. Vier Schichten Mohawk Superfine-Papier. Eine farbige Naht, die ins Auge fällt. Jede Karte trägt einen einzigartigen QR-Code, der zu den Designrichtungen eines bestimmten Raums führt.',
    'agency.cardsDesc2': 'Ein Set pro Angebot: eine Hauskarte für die Haustür und individuelle Raumkarten für jeden Lichtschalter. Käufer scannen, während sie im Raum stehen und sehen drei Designmöglichkeiten für genau den Raum, den sie betrachten.',
    'agency.cardFeature1': '2,56" Quadrat — passt in eine Tasche, steht neben einem Lichtschalter',
    'agency.cardFeature2': 'Einzigartiger QR pro Raum — jede Karte ist ihr eigener Einstiegspunkt',
    'agency.cardFeature3': 'Mit Agentur-Branding — Ihr Logo, der Name Ihres Maklers',
    'agency.cardFeature4': 'An den Makler versandt — bereit für das offene Haus',
    'agency.measuredImpact': 'Gemessene Wirkung',
    'agency.numbersTitle': 'Die Zahlen hinter dem Erlebnis',
    'agency.numbersDesc': 'Anonyme, datenschutzfreundliche Engagement-Daten aus Live-Einsätzen. Es werden niemals persönliche Informationen gesammelt.',
    'agency.avgTime': 'Durchschn. Zeit beim offenen Haus',
    'agency.qrScans': 'QR-Scans pro Angebot',
    'agency.goDeeper': 'Vertiefungs-Rate',
    'agency.returnVisits': 'Wiederholungsbesuche',
    'agency.dataCollecting': 'Datenerfassung',
    'agency.metricsNote': 'Diese Metriken werden aus Live-Room-Einsätzen gefüllt. Wenn Angebote live gehen und Besucher des offenen Hauses sich engagieren, bauen sich die Daten auf. Jeder Scan, jedes erkundete Design, jede verbrachte Minute wird anonym erfasst und hier aggregiert.',
    'agency.proofNote': 'Ihr Maklerbüro erhält das Engagement. Wir verfolgen, wie gut es funktioniert. Gemeinsam beweisen wir, dass designorientierte offene Häuser besser abschneiden.',
    'agency.integration': 'Integration',
    'agency.linksBackToYou': 'Alles verlinkt zurück zu Ihnen',
    'agency.listingsFeatured': 'Angebots-Seiten präsentieren Ihren Makler',
    'agency.listingsFeaturedDesc': 'Jede Room-Angebots-Seite zeigt prominent das Porträt, den Namen und das Maklerbüro Ihres Maklers. Der Käufer sieht Ihre Marke während der gesamten Design-Exploration.',
    'agency.linksToBrokerage': 'Links zu Ihrem Makler-Angebot',
    'agency.linksToBrokerageDesc': 'Die ursprüngliche Angebots-URL ist immer verlinkt. Käufer gelangen von der Design-Inspiration direkt zu Ihrer Makler-Seite mit Preisen, Terminplanung und Kontaktinformationen.',
    'agency.qrCardsIdentity': 'QR-Karten tragen Ihre Identität',
    'agency.qrCardsIdentityDesc': 'Premium-Karten gedruckt mit Ihrem Agentur-Logo und Makler-Namen. Das physische Produkt ist eine Erweiterung Ihrer Marke, keine Drittanbieter-Störung.',
    'agency.designPartner': 'Design-Partner-Empfehlung',
    'agency.designPartnerDesc': 'Eine preisgekrönte lokale Designfirma wird neben Ihren Angeboten vorgestellt. Dies erhöht die Wahrnehmung Ihres Maklerbüros als designbewusst und zukunftsorientiert.',
    'agency.readyToSee': 'Bereit, es in Ihrem Markt zu sehen?',
    'agency.deployNote': 'Wir setzen Room pro Markt mit einem dedizierten Design-Partner ein. Begrenzte Verfügbarkeit — ein Maklerbüro pro Gebiet.',
    'agency.startConversation': 'Gespräch beginnen',
